const cellKey = (x: number, y: number): string => `${x},${y}`;

const countLiveNeighbors = (
  x: number,
  y: number,
  liveSet: ReadonlySet<string>,
): number =>
  NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(cellKey(x + dx, y + dy)))
    .length;

const survivesToNextGeneration = (liveNeighborCount: number): boolean =>
  liveNeighborCount === 2 || liveNeighborCount === 3;

const isBornNextGeneration = (liveNeighborCount: number): boolean =>
  liveNeighborCount === 3;

const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

const uniqueDeadNeighbors = (
  liveCells: Cell[],
  liveSet: ReadonlySet<string>,
): Cell[] => {
  const deadNeighbors = new Map<string, Cell>();
  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor[0], neighbor[1]);
      if (!liveSet.has(key)) deadNeighbors.set(key, neighbor);
    }
  }
  return [...deadNeighbors.values()];
};

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
  const liveNeighborCount = (cell: Cell): number =>
    countLiveNeighbors(cell[0], cell[1], liveSet);

  const survivors = liveCells.filter((cell) =>
    survivesToNextGeneration(liveNeighborCount(cell)),
  );
  const births = uniqueDeadNeighbors(liveCells, liveSet).filter((cell) =>
    isBornNextGeneration(liveNeighborCount(cell)),
  );
  return [...survivors, ...births];
}

